 1→.layout {
 2→  display: grid;
 3→  grid-template-rows: var(--toolbar-height) 1fr;
 4→  grid-template-columns:
 5→    var(--layout-sidebar-width, var(--sidebar-width))
 6→    1fr
 7→    var(--layout-properties-width, var(--properties-width));
 8→  grid-template-areas:
 9→    "toolbar toolbar toolbar"
10→    "sidebar canvas properties";
11→  height: 100%;
12→  width: 100%;
13→}
14→
15→.toolbar {
16→  grid-area: toolbar;
17→  position: relative;
18→  z-index: 10;
19→}
20→
21→.sidebar {
22→  grid-area: sidebar;
23→  min-height: 0;
24→  overflow-y: auto;
25→}
26→
27→.canvas {
28→  grid-area: canvas;
29→  min-width: 0;
30→  min-height: 0;
31→  overflow: hidden;
32→  box-shadow: inset 1px 0 3px rgba(0, 0, 0, 0.04), inset -1px 0 3px rgba(0, 0, 0, 0.04);
33→}
34→
35→.properties {
36→  grid-area: properties;
37→  min-height: 0;
38→  overflow-y: auto;
39→}
40→
41→.modelWorkspace {
42→  display: grid;
43→  grid-template-columns: minmax(0, 1fr) minmax(300px, 28vw);
44→  width: 100%;
45→  height: 100%;
46→  min-width: 0;
47→  min-height: 0;
48→}
49→
50→.primaryCanvas {
51→  min-width: 0;
52→  min-height: 0;
53→}
54→
55→.preview {
56→  display: flex;
57→  min-width: 0;
58→  min-height: 0;
59→  height: 100%;
60→  overflow: hidden;
61→}
62→
63→.previewFallback {
64→  display: flex;
65→  align-items: center;
66→  justify-content: center;
67→  width: 100%;
68→  height: 100%;
69→  min-height: 0;
70→  border-left: 1px solid var(--color-border);
71→  background: linear-gradient(180deg, rgba(255, 255, 255, 0.72), rgba(243, 243, 240, 0.92));
72→  color: var(--color-text-secondary);
73→  font-size: 12px;
74→  font-weight: 600;
75→  letter-spacing: 0.04em;
76→  text-transform: uppercase;
77→}
78→
79→.panelHidden {
80→  display: none;
81→}
82→
83→@media (max-width: 1200px) {
84→  .modelWorkspace {
85→    grid-template-columns: minmax(0, 1fr);
86→    grid-template-rows: minmax(0, 1fr) 280px;
87→  }
88→
89→  .previewFallback {
90→    border-left: none;
91→    border-top: 1px solid var(--color-border);
