 40→function screenToModel(screenX, screenY, viewport, svgRect) {
 41→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 42→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 43→  return { x, y };
 44→}
 45→
 46→export default function SvgCanvas() {
 47→  const svgRef = useRef(null);
 48→  const isPanning = useRef(false);
 49→  const lastPanPos = useRef({ x: 0, y: 0 });
 50→  const spaceHeld = useRef(false);
 51→  const cursorPosRef = useRef({ x: 0, y: 0 });
 52→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 53→
 54→  const { project, dispatch, getFloor } = useProject();
 55→  const editor = useEditor();
 56→  const {
 57→    activeTool, selectedId, selectedType, toolState,
 58→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 59→    regionSelection, pastePreview,
 60→    dispatch: editorDispatch,
 61→  } = editor;
 62→
 63→  const floor = getFloor(activeFloorId);
 64→  const {
 65→    copySelection,
 66→    cutSelection,
 67→    beginPaste,
 68→    updatePastePreview,
 69→    cancelPaste,
 70→    placePaste,
 71→    previewContent,
 72→  } = usePlanClipboardController();
 73→
 74→  const tool = useEditorTool({
 75→    activeTool,
 76→    dispatch,
 77→    editorDispatch,
 78→    project,
 79→    getFloor,
 80→    activeFloorId,
 81→    viewport,
 82→    snapEnabled,
 83→    selectedId,
 84→    selectedType,
 85→    toolState,
 86→    viewMode,
 87→  });
 88→
 89→  const getModelPos = useCallback((e) => {
 90→    const rect = svgRef.current.getBoundingClientRect();
 91→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 92→  }, [viewport]);
 93→
 94→  const handleMouseDown = useCallback((e) => {
 95→    // Middle mouse or space+left for pan
 96→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 97→      isPanning.current = true;
 98→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 99→      e.preventDefault();
100→      return;
101→    }
102→
103→    const modelPos = getModelPos(e);
104→    if (pastePreview?.active && e.button === 0) {
105→      placePaste(modelPos);
106→      return;
107→    }
108→    tool.onMouseDown(modelPos, e);
109→  }, [getModelPos, pastePreview, placePaste, tool]);
110→
111→  const handleMouseMove = useCallback((e) => {
112→    if (isPanning.current) {
113→      const dx = e.clientX - lastPanPos.current.x;
114→      const dy = e.clientY - lastPanPos.current.y;
115→      editorDispatch({ type: 'PAN', dx, dy });
116→      lastPanPos.current = { x: e.clientX, y: e.clientY };
117→      return;
118→    }
119→
120→    const modelPos = getModelPos(e);
121→    cursorPosRef.current = modelPos;
122→    setCursorPos(modelPos);
123→    if (pastePreview?.active) {
124→      updatePastePreview(modelPos);
125→      return;
126→    }
127→    tool.onMouseMove(modelPos, e);
128→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
129→
130→  const handleMouseUp = useCallback((e) => {
131→    if (isPanning.current) {
132→      isPanning.current = false;
133→      return;
134→    }
135→    if (pastePreview?.active) return;
136→    const modelPos = getModelPos(e);
137→    tool.onMouseUp(modelPos, e);
138→  }, [getModelPos, pastePreview, tool]);
139→
140→  const handleDoubleClick = useCallback((e) => {
141→    if (pastePreview?.active) return;
142→    const modelPos = getModelPos(e);
143→    tool.onDoubleClick(modelPos, e);
144→  }, [getModelPos, pastePreview, tool]);
145→
146→  const handleWheel = useCallback((e) => {
147→    e.preventDefault();
148→    const rect = svgRef.current.getBoundingClientRect();
149→    const mouseX = e.clientX - rect.left;
150→    const mouseY = e.clientY - rect.top;
151→
152→    const direction = e.deltaY < 0 ? 1 : -1;
153→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
154→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
155→
156→    // Zoom centered on cursor
157→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
158→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
159→
160→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
161→  }, [viewport, editorDispatch]);
162→
163→  useEffect(() => {
164→    if (!statusMessage) return undefined;
165→
166→    const timer = window.setTimeout(() => {
167→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
168→    }, 2500);
169→
170→    return () => window.clearTimeout(timer);
171→  }, [statusMessage, editorDispatch]);
172→
173→  useEffect(() => {
174→    const handleKeyDown = (e) => {
175→      if (isTypingTarget(e.target)) return;
176→
177→      if (e.key === ' ') {
178→        spaceHeld.current = true;
179→        e.preventDefault();
180→      }
181→
182→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
183→        const key = e.key.toLowerCase();
184→        if (key === 'c') {
185→          e.preventDefault();
186→          copySelection();
187→          return;
188→        }
189→        if (key === 'x') {
190→          e.preventDefault();
191→          cutSelection();
192→          return;
193→        }
194→        if (key === 'v') {
195→          e.preventDefault();
196→          beginPaste(cursorPosRef.current);
197→          return;
198→        }
199→      }
200→
201→      if (e.key === 'Escape' && pastePreview?.active) {
202→        e.preventDefault();
203→        cancelPaste();
204→        return;
205→      }
206→
207→      // Tool shortcuts
208→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
209→        switch (e.key.toLowerCase()) {
210→          case 'v':
211→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
212→            return;
213→          case 'm':
214→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
215→            return;
216→          case 'w':
217→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
218→            return;
219→          case 'b':
220→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
221→            return;
222→          case 't':
223→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
224→            return;
225→          case 'q':
226→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
227→            return;
228→          case 's':
229→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
230→            return;
231→          case 'r':
232→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
233→            return;
234→          case 'd':
235→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
236→            return;
237→          case 'n':
238→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
239→            return;
240→          case 'c':
241→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
242→            return;
243→          case 'l':
244→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
245→            return;
246→        }
247→      }
248→
249→      tool.onKeyDown(e);
250→    };
251→
252→    const handleKeyUp = (e) => {
253→      if (isTypingTarget(e.target)) return;
254→
255→      if (e.key === ' ') {
256→        spaceHeld.current = false;
257→      }
258→    };
259→
260→    window.addEventListener('keydown', handleKeyDown);
261→    window.addEventListener('keyup', handleKeyUp);
262→    return () => {
263→      window.removeEventListener('keydown', handleKeyDown);
264→      window.removeEventListener('keyup', handleKeyUp);
265→    };
266→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
267→
268→  // Prevent default context menu on SVG
269→  useEffect(() => {
270→    const svg = svgRef.current;
271→    if (!svg) return;
272→    const prevent = (e) => e.preventDefault();
273→    svg.addEventListener('contextmenu', prevent);
274→    svg.addEventListener('wheel', handleWheel, { passive: false });
275→    return () => {
276→      svg.removeEventListener('contextmenu', prevent);
277→      svg.removeEventListener('wheel', handleWheel);
278→    };
279→  }, [handleWheel]);
280→
281→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
282→  const zoomPercent = Math.round(viewport.zoom * 1000);
283→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
