  1→import { useCallback, useEffect, useMemo, useRef } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { MAX_ZOOM, MIN_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  5→import { fitViewportToSheet } from '@/sheets/layout';
  6→import { hitTestViewport, hitTestViewportHandle, hitTestViewportRotationHandle } from '@/sheets/hitTest';
  7→import { buildSheetScene } from '@/sheets/layout';
  8→import styles from './SvgCanvas.module.css';
  9→import SheetRenderer from './SheetRenderer';
 10→
 11→function screenToSheet(screenX, screenY, viewport, svgRect) {
 12→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 13→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 14→  return { x, y };
 15→}
 16→
 17→export default function SheetCanvas() {
 18→  const svgRef = useRef(null);
 19→  const dragState = useRef(null);
 20→  const isPanning = useRef(false);
 21→  const lastPanPos = useRef({ x: 0, y: 0 });
 22→
 23→  const { project, dispatch } = useProject();
 24→  const {
 25→    activeSheetId,
 26→    selectedId,
 27→    selectedType,
 28→    viewport,
 29→    dispatch: editorDispatch,
 30→  } = useEditor();
 31→
 32→  const sheet = (project.sheets || []).find((entry) => entry.id === activeSheetId) || null;
 33→  const scene = useMemo(() => buildSheetScene(project, sheet), [project, sheet]);
 34→
 35→  const getSheetPos = useCallback((event) => {
 36→    const rect = svgRef.current.getBoundingClientRect();
 37→    return screenToSheet(event.clientX, event.clientY, viewport, rect);
 38→  }, [viewport]);
 39→
 40→  const updateViewport = useCallback((viewportId, updates) => {
 41→    if (!sheet) return;
 42→    const current = (sheet.viewports || []).find((entry) => entry.id === viewportId);
 43→    if (!current) return;
 44→    const nextViewport = fitViewportToSheet({ ...current, ...updates }, sheet);
 45→    dispatch({ type: 'SHEET_VIEWPORT_UPDATE', sheetId: sheet.id, viewport: nextViewport });
 46→  }, [dispatch, sheet]);
 47→
 48→  const handleMouseDown = useCallback((event) => {
 49→    if (event.button === 1 || (event.button === 0 && event.shiftKey)) {
 50→      isPanning.current = true;
 51→      lastPanPos.current = { x: event.clientX, y: event.clientY };
 52→      event.preventDefault();
 53→      return;
 54→    }
 55→
 56→    if (!sheet || !scene) return;
 57→
 58→    const point = getSheetPos(event);
 59→
 60→    if (selectedType === 'sheetViewport' && selectedId) {
 61→      const selectedVp = scene.viewports.find((entry) => entry.id === selectedId);
 62→      if (selectedVp && hitTestViewportRotationHandle(point, selectedVp, 6 / viewport.zoom)) {
 63→        const cx = selectedVp.x + selectedVp.width / 2;
 64→        const cy = selectedVp.y + selectedVp.height / 2;
 65→        dragState.current = {
 66→          mode: 'rotate',
 67→          viewportId: selectedId,
 68→          center: { x: cx, y: cy },
 69→          initialRotation: selectedVp.rotation || 0,
 70→          startAngle: Math.atan2(point.y - cy, point.x - cx) * (180 / Math.PI),
 71→        };
 72→        return;
 73→      }
 74→    }
 75→
 76→    const handleHit = selectedType === 'sheetViewport' && selectedId
 77→      ? hitTestViewportHandle(point, scene.viewports.filter((entry) => entry.id === selectedId), 6 / viewport.zoom)
 78→      : null;
 79→
 80→    if (handleHit) {
 81→      dragState.current = {
 82→        mode: 'resize',
 83→        viewportId: handleHit.viewportId,
 84→        handle: handleHit.handle,
 85→        origin: point,
 86→        initialViewport: sheet.viewports.find((entry) => entry.id === handleHit.viewportId),
 87→      };
 88→      return;
 89→    }
 90→
 91→    const viewportHit = hitTestViewport(point, scene.viewports);
 92→    if (viewportHit) {
 93→      editorDispatch({ type: 'SELECT_OBJECT', id: viewportHit.id, objectType: 'sheetViewport' });
 94→      dragState.current = {
 95→        mode: 'move',
 96→        viewportId: viewportHit.id,
 97→        origin: point,
 98→        initialViewport: sheet.viewports.find((entry) => entry.id === viewportHit.id),
 99→      };
100→      return;
101→    }
102→
103→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
104→    dragState.current = null;
105→  }, [editorDispatch, getSheetPos, scene, selectedId, selectedType, sheet, viewport.zoom]);
106→
107→  const handleMouseMove = useCallback((event) => {
108→    if (isPanning.current) {
109→      const dx = event.clientX - lastPanPos.current.x;
110→      const dy = event.clientY - lastPanPos.current.y;
111→      editorDispatch({ type: 'PAN', dx, dy });
112→      lastPanPos.current = { x: event.clientX, y: event.clientY };
113→      return;
114→    }
115→
116→    if (!dragState.current || !sheet) return;
117→
118→    const point = getSheetPos(event);
119→    const { mode } = dragState.current;
120→
121→    if (mode === 'rotate') {
122→      const { center, initialRotation, startAngle, viewportId } = dragState.current;
123→      const currentAngle = Math.atan2(point.y - center.y, point.x - center.x) * (180 / Math.PI);
124→      let newRotation = initialRotation + (currentAngle - startAngle);
125→      if (event.shiftKey) {
126→        newRotation = Math.round(newRotation / 15) * 15;
127→      }
128→      newRotation = ((newRotation % 360) + 360) % 360;
129→      updateViewport(viewportId, { rotation: newRotation });
130→      return;
131→    }
132→
133→    const { initialViewport, origin, handle, viewportId } = dragState.current;
134→    const dx = point.x - origin.x;
135→    const dy = point.y - origin.y;
136→
137→    if (mode === 'move') {
138→      updateViewport(viewportId, {
139→        x: initialViewport.x + dx,
140→        y: initialViewport.y + dy,
141→      });
142→      return;
143→    }
144→
145→    const next = {
146→      x: initialViewport.x,
147→      y: initialViewport.y,
148→      width: initialViewport.width,
149→      height: initialViewport.height,
150→    };
151→
152→    if (handle.includes('n')) {
153→      next.y = initialViewport.y + dy;
154→      next.height = initialViewport.height - dy;
155→    }
156→    if (handle.includes('s')) {
157→      next.height = initialViewport.height + dy;
158→    }
159→    if (handle.includes('w')) {
160→      next.x = initialViewport.x + dx;
161→      next.width = initialViewport.width - dx;
162→    }
163→    if (handle.includes('e')) {
164→      next.width = initialViewport.width + dx;
165→    }
166→
167→    updateViewport(viewportId, next);
168→  }, [editorDispatch, getSheetPos, sheet, updateViewport]);
169→
170→  const handleMouseUp = useCallback(() => {
171→    isPanning.current = false;
172→    dragState.current = null;
173→  }, []);
174→
175→  const handleWheel = useCallback((event) => {
176→    event.preventDefault();
177→    const rect = svgRef.current.getBoundingClientRect();
178→    const mouseX = event.clientX - rect.left;
179→    const mouseY = event.clientY - rect.top;
180→    const direction = event.deltaY < 0 ? 1 : -1;
181→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
182→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
183→    const panX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
184→    const panY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
185→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX, panY });
186→  }, [editorDispatch, viewport]);
187→
188→  useEffect(() => {
189→    const svg = svgRef.current;
190→    if (!svg) return undefined;
191→    const prevent = (event) => event.preventDefault();
192→    svg.addEventListener('contextmenu', prevent);
193→    svg.addEventListener('wheel', handleWheel, { passive: false });
194→    return () => {
195→      svg.removeEventListener('contextmenu', prevent);
196→      svg.removeEventListener('wheel', handleWheel);
197→    };
198→  }, [handleWheel]);
199→
200→  return (
201→    <div className={styles.canvasContainer}>
202→      <svg
203→        ref={svgRef}
204→        className={styles.svg}
205→        style={{ cursor: dragState.current ? 'grabbing' : 'default' }}
206→        onMouseDown={handleMouseDown}
207→        onMouseMove={handleMouseMove}
208→        onMouseUp={handleMouseUp}
209→      >
210→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
211→          {sheet ? (
212→            <SheetRenderer
213→              project={project}
214→              sheet={sheet}
215→              selectedId={selectedId}
216→              selectedType={selectedType}
217→            />
218→          ) : (
219→            <g className="sheet-empty">
220→              <rect x={0} y={0} width={420} height={297} fill="#f6f7f9" stroke="#d0d6de" strokeDasharray="2 2" />
221→              <text x={210} y={148} textAnchor="middle" dominantBaseline="middle" fill="#66768a" fontSize={12}>
222→                Create a sheet from the sidebar or properties panel.
223→              </text>
224→            </g>
225→          )}
226→        </g>
227→      </svg>
228→      {sheet && scene && (
229→        <svg
230→          data-sheet-export-root="true"
231→          width={scene.paper.width}
232→          height={scene.paper.height}
233→          viewBox={`0 0 ${scene.paper.width} ${scene.paper.height}`}
234→          style={{
235→            position: 'absolute',
236→            width: 0,
237→            height: 0,
238→            overflow: 'hidden',
239→            pointerEvents: 'none',
240→            opacity: 0,
241→          }}
242→          aria-hidden="true"
243→        >
244→          <SheetRenderer
245→            project={project}
246→            sheet={sheet}
247→            selectedId={null}
248→            selectedType={null}
249→          />
250→        </svg>
251→      )}
252→      <div className={styles.statusBar}>
253→        <span>Workspace: sheet</span>
254→        <span>Sheet: {sheet?.title || 'None'}</span>
255→        <span>Zoom: {Math.round(viewport.zoom * 100)}%</span>
256→      </div>
257→    </div>
258→  );
259→}
