 30→              stroke="#4c5b70"
 31→              strokeWidth={0.35}
 32→            />
 33→            <line
 34→              x1={titleBlock.x + titleBlock.width * 0.28}
 35→              y1={y}
 36→              x2={titleBlock.x + titleBlock.width * 0.28}
 37→              y2={y + rowHeight}
 38→              stroke="#4c5b70"
 39→              strokeWidth={0.35}
