 69→export default function SheetRenderer({ project, sheet, selectedId, selectedType }) {
 70→  const scene = buildSheetScene(project, sheet);
 71→  if (!scene) return null;
 72→
 73→  return (
 74→    <g className="sheet">
 75→      <rect
 76→        x={0}
 77→        y={0}
 78→        width={scene.paper.width}
 79→        height={scene.paper.height}
 80→        fill="#f2f4f7"
 81→        stroke="none"
 82→      />
 83→      <rect
 84→        x={scene.border.x}
 85→        y={scene.border.y}
 86→        width={scene.border.width}
 87→        height={scene.border.height}
 88→        fill="#ffffff"
 89→        stroke={selectedType === 'sheet' && selectedId === sheet.id ? '#0f8f74' : '#4c5b70'}
 90→        strokeWidth={selectedType === 'sheet' && selectedId === sheet.id ? 1 : 0.7}
 91→      />
 92→      <TitleBlock titleBlock={scene.titleBlock} />
 93→      {scene.viewports.map((viewport) => {
 94→        const isSelected = selectedType === 'sheetViewport' && selectedId === viewport.id;
 95→        return (
 96→          <g
 97→            key={viewport.id}
 98→            className="sheet-viewport"
 99→            transform={viewport.rotation ? `rotate(${viewport.rotation}, ${viewport.x + viewport.width / 2}, ${viewport.y + viewport.height / 2})` : undefined}
100→          >
101→            <text
102→              x={viewport.x}
103→              y={viewport.y - 2}
104→              fontSize={3.4}
105→              fill="#4c5b70"
106→            >
107→              {viewport.title}
108→            </text>
109→            <rect
110→              x={viewport.x}
111→              y={viewport.y}
112→              width={viewport.width}
113→              height={viewport.height}
114→              fill="#ffffff"
115→              stroke={isSelected ? '#0f8f74' : '#4c5b70'}
116→              strokeWidth={isSelected ? 0.8 : 0.45}
117→            />
118→            {viewport.source.kind === 'empty' ? (
119→              <EmptyViewportMessage viewport={viewport} message={viewport.source.message} />
120→            ) : (
121→              <svg
122→                x={viewport.clipRect.x}
123→                y={viewport.clipRect.y}
124→                width={viewport.clipRect.width}
125→                height={viewport.clipRect.height}
126→                viewBox={`0 0 ${viewport.clipRect.width} ${viewport.clipRect.height}`}
127→                overflow="hidden"
128→              >
129→                <g transform={`translate(${viewport.contentTransform.translateX}, ${viewport.contentTransform.translateY}) scale(${viewport.contentTransform.scale})`}>
130→                  <SheetViewportContent source={viewport.source} />
131→                </g>
132→              </svg>
133→            )}
134→            {isSelected && Object.values(getViewportHandleRects(viewport, HANDLE_SIZE)).map((handleRect) => (
135→              <rect
136→                key={`${viewport.id}-${handleRect.x}-${handleRect.y}`}
137→                x={handleRect.x}
138→                y={handleRect.y}
139→                width={handleRect.width}
140→                height={handleRect.height}
141→                fill="#ffffff"
142→                stroke="#0f8f74"
143→                strokeWidth={0.5}
144→              />
145→            ))}
146→            {isSelected && (() => {
147→              const rh = getViewportRotationHandle(viewport, HANDLE_SIZE);
148→              return (
149→                <>
150→                  <line
151→                    x1={rh.stemX}
152→                    y1={rh.stemY1}
153→                    x2={rh.stemX}
154→                    y2={rh.stemY2}
155→                    stroke="#0f8f74"
156→                    strokeWidth={0.4}
157→                  />
158→                  <circle
159→                    cx={rh.cx}
160→                    cy={rh.cy}
161→                    r={rh.radius}
162→                    fill="#ffffff"
163→                    stroke="#0f8f74"
164→                    strokeWidth={0.5}
165→                    style={{ cursor: 'grab' }}
166→                  />
167→                </>
168→              );
169→            })()}
170→          </g>
171→        );
172→      })}
173→    </g>
174→  );
175→}
