 56→export default function SelectionOverlay({ selectedId, selectedType, floor, zoom }) {
 57→  if (!selectedId || !floor) return null;
 58→
 59→  if (selectedType === 'slab') {
 60→    const slab = (floor.slabs || []).find(s => s.id === selectedId) || null;
 61→    const renderData = slab ? getSlabRenderData(slab) : null;
 62→    if (!renderData) return null;
 63→
 64→    const handleR = HANDLE_SIZE / zoom;
 65→    return (
 66→      <g>
 67→        <polygon
 68→          points={renderData.points}
 69→          fill="var(--color-selection-fill)"
 70→          stroke="var(--color-selection)"
 71→          strokeWidth={2}
 72→          strokeDasharray="6 3"
 73→          vectorEffect="non-scaling-stroke"
 74→        />
 75→        {renderData.outline.map((point, index) => (
 76→          <rect
 77→            key={`${point.x}-${point.y}-${index}`}
 78→            data-handle="slab-vertex"
 79→            data-index={index}
 80→            x={point.x - handleR / 2}
 81→            y={point.y - handleR / 2}
 82→            width={handleR}
 83→            height={handleR}
 84→            fill="white"
 85→            stroke="var(--color-selection)"
 86→            strokeWidth={2}
 87→            vectorEffect="non-scaling-stroke"
 88→            style={{ cursor: 'move' }}
 89→          />
 90→        ))}
 91→      </g>
 92→    );
 93→  }
 94→
 95→  if (selectedType === 'wall') {
 96→    const wall = floor.walls.find(w => w.id === selectedId);
 97→    if (!wall) return null;
 98→    return <WallSelection wall={wall} columns={floor.columns || []} zoom={zoom} />;
 99→  }
100→
101→  if (selectedType === 'sectionCut') {
102→    const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId) || null;
103→    const renderData = getSectionCutRenderData(sectionCut);
104→    if (!renderData) return null;
105→    const handleR = HANDLE_SIZE / zoom;
106→
107→    return (
108→      <g>
109→        <line
110→          x1={renderData.line.start.x}
111→          y1={renderData.line.start.y}
112→          x2={renderData.line.end.x}
113→          y2={renderData.line.end.y}
114→          stroke="var(--color-selection)"
115→          strokeWidth={2}
116→          strokeDasharray="6 3"
117→          vectorEffect="non-scaling-stroke"
118→        />
119→        <rect
120→          data-handle="start"
121→          x={sectionCut.startPoint.x - handleR / 2}
122→          y={sectionCut.startPoint.y - handleR / 2}
123→          width={handleR}
124→          height={handleR}
125→          fill="white"
126→          stroke="var(--color-selection)"
127→          strokeWidth={2}
128→          vectorEffect="non-scaling-stroke"
129→          style={{ cursor: 'move' }}
130→        />
131→        <rect
132→          data-handle="end"
133→          x={sectionCut.endPoint.x - handleR / 2}
134→          y={sectionCut.endPoint.y - handleR / 2}
135→          width={handleR}
136→          height={handleR}
137→          fill="white"
138→          stroke="var(--color-selection)"
139→          strokeWidth={2}
140→          vectorEffect="non-scaling-stroke"
141→          style={{ cursor: 'move' }}
142→        />
143→      </g>
144→    );
145→  }
146→
147→  if (selectedType === 'annotation') {
148→    const figure = getManualAnnotationFigure(floor, selectedId);
149→    if (!figure) return null;
150→    return (
151→      <g>
152→        {figure.extensionLines.map((line, index) => (
153→          <line
154→            key={`annotation-ext-${index}`}
155→            x1={line.start.x}
156→            y1={line.start.y}
157→            x2={line.end.x}
158→            y2={line.end.y}
159→            stroke="var(--color-selection)"
160→            strokeWidth={2}
161→            strokeDasharray="6 3"
162→            vectorEffect="non-scaling-stroke"
163→          />
164→        ))}
165→        <line
166→          x1={figure.lineStart.x}
167→          y1={figure.lineStart.y}
168→          x2={figure.lineEnd.x}
169→          y2={figure.lineEnd.y}
170→          stroke="var(--color-selection)"
171→          strokeWidth={2}
172→          strokeDasharray="6 3"
173→          vectorEffect="non-scaling-stroke"
174→        />
175→      </g>
176→    );
177→  }
178→
179→  if (selectedType === 'door') {
180→    const door = floor.doors.find(d => d.id === selectedId);
181→    if (!door) return null;
182→    const wall = floor.walls.find(w => w.id === door.wallId);
183→    if (!wall) return null;
184→    // Highlight parent wall subtly
185→    const outline = getWallRenderData(wall, floor.columns || []).outline;
186→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
187→    return (
188→      <polygon
189→        points={points}
190→        fill="none"
191→        stroke="var(--color-selection)"
192→        strokeWidth={2}
193→        strokeDasharray="6 3"
194→        vectorEffect="non-scaling-stroke"
195→      />
196→    );
197→  }
198→
199→  if (selectedType === 'beam') {
200→    const beam = (floor.beams || []).find(b => b.id === selectedId);
201→    if (!beam) return null;
202→    const renderData = getBeamRenderData(beam, floor.columns || []);
203→    if (!renderData) return null;
204→    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
205→    return (
206→      <polygon
207→        points={points}
208→        fill="var(--color-selection-fill)"
209→        stroke="var(--color-selection)"
210→        strokeWidth={2}
211→        strokeDasharray="6 3"
212→        vectorEffect="non-scaling-stroke"
213→      />
214→    );
215→  }
216→
217→  if (selectedType === 'stair') {
218→    const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
219→    if (!stair) return null;
220→    const renderData = getStairRenderData(stair);
221→    if (!renderData) return null;
222→    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
223→    return (
224→      <polygon
225→        points={points}
226→        fill="var(--color-selection-fill)"
227→        stroke="var(--color-selection)"
228→        strokeWidth={2}
229→        strokeDasharray="6 3"
230→        vectorEffect="non-scaling-stroke"
231→      />
232→    );
233→  }
234→
235→  if (selectedType === 'landing') {
236→    const landing = (floor.landings || []).find(l => l.id === selectedId);
237→    if (!landing) return null;
238→    const renderData = getLandingRenderData(landing);
239→    if (!renderData) return null;
240→    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
241→    return (
242→      <polygon
243→        points={points}
244→        fill="var(--color-selection-fill)"
245→        stroke="var(--color-selection)"
246→        strokeWidth={2}
247→        strokeDasharray="6 3"
248→        vectorEffect="non-scaling-stroke"
249→      />
250→    );
251→  }
252→
253→  if (selectedType === 'window') {
254→    const win = floor.windows.find(w => w.id === selectedId);
255→    if (!win) return null;
256→    const wall = floor.walls.find(w => w.id === win.wallId);
257→    if (!wall) return null;
258→    const outline = getWallRenderData(wall, floor.columns || []).outline;
259→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
260→    return (
261→      <polygon
262→        points={points}
263→        fill="none"
264→        stroke="var(--color-selection)"
265→        strokeWidth={2}
266→        strokeDasharray="6 3"
267→        vectorEffect="non-scaling-stroke"
268→      />
269→    );
270→  }
271→
272→  if (selectedType === 'column') {
273→    const column = (floor.columns || []).find(c => c.id === selectedId);
274→    if (!column) return null;
275→    const outline = columnOutline(column);
276→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
277→    const handleR = HANDLE_SIZE / zoom;
278→    return (
279→      <g>
280→        <polygon
281→          points={points}
282→          fill="var(--color-selection-fill)"
283→          stroke="var(--color-selection)"
284→          strokeWidth={2}
285→          strokeDasharray="6 3"
286→          vectorEffect="non-scaling-stroke"
287→        />
288→        {outline.map((p, i) => (
289→          <rect
290→            key={i}
291→            x={p.x - handleR / 2}
292→            y={p.y - handleR / 2}
293→            width={handleR}
294→            height={handleR}
295→            fill="white"
296→            stroke="var(--color-selection)"
297→            strokeWidth={2}
298→            vectorEffect="non-scaling-stroke"
299→            style={{ cursor: 'move' }}
300→          />
301→        ))}
302→      </g>
303→    );
304→  }
305→
306→  if (selectedType === 'room') {
307→    const room = floor.rooms.find(r => r.id === selectedId);
308→    if (!room?.points?.length) return null;
309→    const points = room.points.map(p => `${p.x},${p.y}`).join(' ');
310→    return (
311→      <polygon
312→        points={points}
313→        fill="none"
314→        stroke="var(--color-selection)"
315→        strokeWidth={2}
316→        strokeDasharray="6 3"
317→        vectorEffect="non-scaling-stroke"
318→      />
319→    );
320→  }
321→
322→  return null;
323→}
