 27→function useUnits() {
 28→  const [unit, setUnit] = useState('mm');
 29→  const isMm = unit === 'mm';
 30→  return {
 31→    unit,
 32→    setUnit,
 33→    suffix: isMm ? 'mm' : 'm',
 34→    toDisplay: (mm) => isMm ? Math.round(mm) : +(mm / 1000).toFixed(3),
 35→    fromDisplay: (v) => isMm ? v : v * 1000,
 36→    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
 37→  };
 38→}
