  1→import { useCallback, useMemo } from 'react';
  2→import { useClipboard } from '@/app/ClipboardProvider';
  3→import { useEditor } from '@/app/EditorProvider';
  4→import { useProject } from '@/app/ProjectProvider';
  5→import {
  6→  buildPlanClipboardPayload,
  7→  countPlanContent,
  8→  cutPlanSelectionFromFloor,
  9→  materializePlanClipboardContent,
 10→  pastePlanClipboardOnFloor,
 11→} from './planClipboard';
 12→
 13→function pluralize(count, noun) {
 14→  return `${count} ${noun}${count === 1 ? '' : 's'}`;
 15→}
 16→
 17→export function usePlanClipboardController() {
 18→  const { project, dispatch, getFloor } = useProject();
 19→  const editor = useEditor();
 20→  const { clipboard, hasClipboard, setClipboard } = useClipboard();
 21→  const {
 22→    activeFloorId,
 23→    workspaceMode,
 24→    viewMode,
 25→    regionSelection,
 26→    pastePreview,
 27→    dispatch: editorDispatch,
 28→  } = editor;
 29→
 30→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 31→  const floor = getFloor(activeFloorId);
 32→
 33→  const previewContent = useMemo(() => {
 34→    if (!pastePreview?.active || !clipboard || !pastePreview.point) return null;
 35→    return materializePlanClipboardContent(clipboard, pastePreview.point);
 36→  }, [clipboard, pastePreview]);
 37→
 38→  const captureSelection = useCallback((store = true) => {
 39→    if (!isPlanView || !floor) {
 40→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Clipboard works only in the plan editor.' });
 41→      return null;
 42→    }
 43→
 44→    if (!regionSelection?.objectCount) {
 45→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Drag a selection region first.' });
 46→      return null;
 47→    }
 48→
 49→    const payload = buildPlanClipboardPayload({
 50→      projectId: project.id,
 51→      floorId: activeFloorId,
 52→      floor,
 53→      regionSelection,
 54→    });
 55→
 56→    if (!payload.objectCount) {
 57→      editorDispatch({
 58→        type: 'SET_STATUS_MESSAGE',
 59→        message: 'Nothing copyable was found in the selected region.',
 60→      });
 61→      return null;
 62→    }
 63→
 64→    if (store) {
 65→      setClipboard(payload);
 66→    }
 67→    return payload;
 68→  }, [activeFloorId, editorDispatch, floor, isPlanView, project.id, regionSelection, setClipboard]);
 69→
 70→  const copySelection = useCallback(() => {
 71→    const payload = captureSelection();
 72→    if (!payload) return false;
 73→
 74→    const skipped = Math.max(0, (payload.sourceSelectionCount || 0) - payload.objectCount);
 75→    editorDispatch({
 76→      type: 'SET_STATUS_MESSAGE',
 77→      message: skipped
 78→        ? `Copied ${pluralize(payload.objectCount, 'object')}; ${pluralize(skipped, 'item')} skipped because required references were not selected.`
 79→        : `Copied ${pluralize(payload.objectCount, 'object')}.`,
 80→    });
 81→    return true;
 82→  }, [captureSelection, editorDispatch]);
 83→
 84→  const cutSelection = useCallback(() => {
 85→    const payload = captureSelection(false);
 86→    if (!payload) return false;
 87→
 88→    const nextFloor = cutPlanSelectionFromFloor(floor, regionSelection.selection);
 89→    const removedCount = countPlanContent(floor) - countPlanContent(nextFloor);
 90→
 91→    if (payload.objectCount !== payload.sourceSelectionCount || removedCount !== payload.objectCount) {
 92→      editorDispatch({
 93→        type: 'SET_STATUS_MESSAGE',
 94→        message: 'Cut requires every dependent item that would be removed to be fully selected. Expand the region and try again.',
 95→      });
 96→      return false;
 97→    }
 98→
 99→    setClipboard(payload);
100→    dispatch({ type: 'FLOOR_REPLACE', floorId: activeFloorId, floor: nextFloor });
101→    editorDispatch({ type: 'DESELECT' });
102→    editorDispatch({
103→      type: 'SET_STATUS_MESSAGE',
104→      message: `Cut ${pluralize(payload.objectCount, 'object')}. Load another project and paste into its plan.`,
105→    });
106→    return true;
107→  }, [activeFloorId, captureSelection, dispatch, editorDispatch, floor, regionSelection, setClipboard]);
108→
109→  const beginPaste = useCallback((point = null) => {
110→    if (!isPlanView || !floor) {
111→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Paste works only in the plan editor.' });
112→      return false;
113→    }
114→    if (!hasClipboard || !clipboard) {
115→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Clipboard is empty.' });
116→      return false;
117→    }
118→
119→    editorDispatch({
120→      type: 'START_PASTE_PREVIEW',
121→      point,
122→    });
123→    editorDispatch({
124→      type: 'SET_STATUS_MESSAGE',
125→      message: 'Move the cursor over the destination plan and click to place the clipboard.',
126→    });
127→    return true;
128→  }, [clipboard, editorDispatch, floor, hasClipboard, isPlanView]);
129→
130→  const updatePastePreview = useCallback((point) => {
131→    if (!pastePreview?.active) return;
132→    editorDispatch({ type: 'UPDATE_PASTE_PREVIEW', point });
133→  }, [editorDispatch, pastePreview]);
134→
135→  const cancelPaste = useCallback(() => {
136→    if (!pastePreview?.active) return;
137→    editorDispatch({ type: 'CANCEL_PASTE_PREVIEW' });
138→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Paste cancelled.' });
139→  }, [editorDispatch, pastePreview]);
140→
141→  const placePaste = useCallback((point) => {
142→    if (!pastePreview?.active || !clipboard || !floor) return false;
143→
144→    const result = pastePlanClipboardOnFloor({
145→      floor,
146→      floorId: activeFloorId,
147→      payload: clipboard,
148→      placementPoint: point,
149→    });
150→
151→    if (!result.insertedCount) {
152→      editorDispatch({
153→        type: 'SET_STATUS_MESSAGE',
154→        message: 'Nothing could be pasted into this floor.',
155→      });
156→      editorDispatch({ type: 'CANCEL_PASTE_PREVIEW' });
157→      return false;
158→    }
159→
160→    dispatch({ type: 'FLOOR_REPLACE', floorId: activeFloorId, floor: result.nextFloor });
161→    if (result.insertedBounds) {
162→      editorDispatch({
163→        type: 'SET_REGION_SELECTION',
164→        bounds: result.insertedBounds,
165→        selection: result.insertedSelection,
166→      });
167→    } else {
168→      editorDispatch({ type: 'DESELECT' });
169→    }
170→    editorDispatch({ type: 'CANCEL_PASTE_PREVIEW' });
171→    editorDispatch({
172→      type: 'SET_STATUS_MESSAGE',
173→      message: `Pasted ${pluralize(result.insertedCount, 'object')}.`,
174→    });
175→    return true;
176→  }, [activeFloorId, clipboard, dispatch, editorDispatch, floor, pastePreview]);
177→
178→  return {
179→    isPlanView,
180→    canCopySelection: Boolean(isPlanView && regionSelection?.objectCount),
181→    canPaste: Boolean(isPlanView && hasClipboard && floor),
182→    hasClipboard,
183→    regionSelection,
184→    pastePreview,
185→    previewContent,
186→    copySelection,
187→    cutSelection,
188→    beginPaste,
189→    updatePastePreview,
190→    cancelPaste,
191→    placePaste,
192→  };
193→}
