 75→export default function Toolbar({
 76→  onNew,
 77→  onSave,
 78→  onLoad,
 79→  isSidebarCollapsed,
 80→  isPropertiesCollapsed,
 81→  onToggleSidebar,
 82→  onToggleProperties,
 83→}) {
 84→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, dispatch: editorDispatch } = useEditor();
 85→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 86→  const {
 87→    canCopySelection,
 88→    canPaste,
 89→    copySelection,
 90→    cutSelection,
 91→    beginPaste,
 92→  } = usePlanClipboardController();
 93→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 94→
 95→  const [toolMenuOpen, setToolMenuOpen] = useState(false);
 96→  const toolMenuRef = useRef(null);
 97→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 98→
 99→  const toolItems = [
100→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V' },
101→    { tool: TOOLS.DIMENSION, label: 'Dim', shortcut: 'M' },
102→    { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W' },
103→    { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B' },
104→    { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T' },
105→    { tool: TOOLS.SECTION, label: 'Section', shortcut: 'Q' },
106→    { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S' },
107→    { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R' },
108→    { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', hint: 'F to flip swing' },
109→    { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N' },
110→    { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C' },
111→    { tool: TOOLS.LANDING, label: 'Landing', shortcut: 'L' },
112→  ];
113→  const activeToolLabel = toolItems.find(t => t.tool === activeTool)?.label || 'Tools';
114→  const handleUndo = useCallback(() => {
115→    if (!canUndo) return;
116→    dispatch({ type: 'UNDO' });
117→    editorDispatch({ type: 'DESELECT' });
118→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
119→  }, [canUndo, dispatch, editorDispatch]);
120→  const handleRedo = useCallback(() => {
121→    if (!canRedo) return;
122→    dispatch({ type: 'REDO' });
123→    editorDispatch({ type: 'DESELECT' });
124→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
125→  }, [canRedo, dispatch, editorDispatch]);
126→
127→  const handleDetectRooms = () => {
128→    const floor = project.floors.find(f => f.id === activeFloorId);
129→    if (!floor || floor.walls.length < 3) {
130→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
131→      return;
132→    }
133→
134→    const detected = detectRooms(floor.walls, floor.columns || []);
135→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
136→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
137→    editorDispatch({ type: 'DESELECT' });
138→    editorDispatch({
139→      type: 'SET_STATUS_MESSAGE',
140→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
141→    });
142→  };
143→
144→  useEffect(() => {
145→    const handleKeyDown = (e) => {
146→      if (!(e.ctrlKey || e.metaKey)) return;
147→      if (isTypingTarget(e.target)) return;
148→
149→      const key = e.key.toLowerCase();
150→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
151→      const isUndo = key === 'z' && !e.shiftKey;
152→      if (!isUndo && !isRedo) return;
153→
154→      e.preventDefault();
155→      if (isRedo) {
156→        handleRedo();
157→        return;
158→      }
159→      handleUndo();
160→    };
161→
162→    window.addEventListener('keydown', handleKeyDown);
163→    return () => window.removeEventListener('keydown', handleKeyDown);
164→  }, [handleRedo, handleUndo]);
165→
166→  useEffect(() => {
167→    if (!toolMenuOpen) return;
168→    const handleClickOutside = (e) => {
169→      if (toolMenuRef.current && !toolMenuRef.current.contains(e.target)) {
170→        setToolMenuOpen(false);
171→      }
172→    };
173→    document.addEventListener('mousedown', handleClickOutside);
174→    return () => document.removeEventListener('mousedown', handleClickOutside);
175→  }, [toolMenuOpen]);
