231→        <button
232→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'plan' ? styles.active : ''}`}
233→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' })}
234→          title="Plan View"
235→        >
236→          Plan
237→        </button>
238→        <button
239→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_front' ? styles.active : ''}`}
240→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_front' })}
241→          title="Front Elevation"
242→        >
243→          Front
244→        </button>
