108→function AppInner() {
109→  const { project, isDirty, dispatch } = useProject();
110→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
111→  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
112→  const initialActiveFloorId = getDefaultActiveFloorId(project);
113→  const [showLoadModal, setShowLoadModal] = useState(false);
114→  const [savedProjects, setSavedProjects] = useState([]);
115→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
116→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
117→  const [projectFileHandle, setProjectFileHandle] = useState(null);
118→  const importInputRef = useRef(null);
119→
120→  useAutosave(project, isDirty, dispatch);
121→
122→  // beforeunload warning
123→  useEffect(() => {
124→    const handler = (e) => {
125→      if (isDirty) {
126→        e.preventDefault();
127→        e.returnValue = '';
128→      }
129→    };
130→    window.addEventListener('beforeunload', handler);
131→    return () => window.removeEventListener('beforeunload', handler);
132→  }, [isDirty]);
133→
134→  const handleNew = useCallback(() => {
135→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
136→    setProjectFileHandle(null);
137→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
138→  }, [isDirty, dispatch]);
139→
140→  const handleSave = useCallback(async () => {
141→    try {
142→      const { fileHandle } = await exportProjectFile(project, { fileHandle: projectFileHandle });
143→      setProjectFileHandle(fileHandle);
144→      try {
145→        await saveProject(project);
146→      } catch {
147→        // Browser draft sync is secondary to file save.
148→      }
149→      dispatch({ type: 'MARK_SAVED' });
150→    } catch (err) {
151→      if (isFilePickerAbortError(err)) return;
152→      alert('Failed to save project file: ' + err.message);
153→    }
154→  }, [project, projectFileHandle, dispatch]);
155→
156→  // Ctrl+S save
157→  useEffect(() => {
158→    const handler = (e) => {
159→      if (isTypingTarget(e.target)) return;
160→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
161→        e.preventDefault();
162→        handleSave();
163→      }
164→    };
165→    window.addEventListener('keydown', handler);
166→    return () => window.removeEventListener('keydown', handler);
167→  }, [handleSave]);
168→
169→  const handleLoadClick = useCallback(async () => {
170→    setSavedProjects(await listProjects());
171→    setShowLoadModal(true);
172→  }, []);
173→
174→  const handleOpenProjectFile = useCallback(async () => {
175→    if (typeof window.showOpenFilePicker !== 'function') {
176→      importInputRef.current?.click();
177→      return;
178→    }
179→
180→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
181→      return;
182→    }
183→
184→    try {
185→      const { project: loaded, savedAt, fileHandle } = await openProjectFile();
186→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
187→      setProjectFileHandle(fileHandle);
188→      setShowLoadModal(false);
189→    } catch (err) {
190→      if (isFilePickerAbortError(err)) return;
191→      alert('Failed to import project file: ' + err.message);
192→    }
193→  }, [isDirty, dispatch]);
194→
195→  const handleImportFile = useCallback(async (e) => {
196→    const file = e.target.files?.[0] || null;
197→    e.target.value = '';
198→    if (!file) return;
199→
200→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
201→      return;
202→    }
203→
204→    try {
205→      const { project: loaded, savedAt } = await importProjectFile(file);
206→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
207→      setProjectFileHandle(null);
208→      setShowLoadModal(false);
209→    } catch (err) {
210→      alert('Failed to import project file: ' + err.message);
211→    }
212→  }, [isDirty, dispatch]);
213→
214→  const handleLoad = useCallback(async (id) => {
215→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
216→    try {
217→      const { project: loaded, savedAt } = await loadProject(id);
218→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
219→      setProjectFileHandle(null);
220→      setShowLoadModal(false);
221→    } catch (err) {
222→      alert('Failed to load project: ' + err.message);
223→    }
224→  }, [isDirty, dispatch]);
225→
226→  const handleDelete = useCallback(async (id, name) => {
227→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
228→    if (!confirmed) return;
229→
230→    try {
231→      await deleteProject(id);
232→      setSavedProjects(projects => projects.filter(project => project.id !== id));
233→    } catch (err) {
234→      alert('Failed to delete project: ' + err.message);
235→    }
236→  }, []);
237→
238→  return (
239→    <EditorProvider
240→      initialActiveFloorId={initialActiveFloorId}
241→      availableFloorIds={availableFloorIds}
242→    >
243→      <input
244→        ref={importInputRef}
245→        type="file"
246→        accept=".json,application/json"
247→        onChange={handleImportFile}
248→        style={{ display: 'none' }}
249→      />
250→
251→      <EditorShell
252→        project={project}
253→        handleNew={handleNew}
254→        handleSave={handleSave}
255→        handleLoadClick={handleLoadClick}
256→        isSidebarCollapsed={isSidebarCollapsed}
257→        isPropertiesCollapsed={isPropertiesCollapsed}
258→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
259→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
260→      />
